import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.Response

object IoTClient {
    private val client = OkHttpClient()

    fun sendRequest(url: String, method: String, body: RequestBody? = null): Response {
        val requestBuilder = Request.Builder().url(url)

        when (method) {
            "GET" -> requestBuilder.get()
            "POST" -> requestBuilder.post(body)
            "PUT" -> requestBuilder.put(body)
            "DELETE" -> requestBuilder.delete()
            else -> throw IllegalArgumentException("Unsupported HTTP method")
        }

        return client.newCall(requestBuilder.build()).execute()
    }
}

// Usage example
fun main() {
    val url = "http://192.168.x.x/api"
    val requestBody = RequestBody.create(MediaType.parse("application/json"), "{\"key\":\"value\"}")

    try {
        val response = IoTClient.sendRequest(url, "POST", requestBody)
        if (response.isSuccessful) {
            println(response.body?.string())
        } else {
            println("Request failed: ${response.code}")
        }
    } catch (e: IOException) {
        e.printStackTrace()
    }
}